  'Time: 1 minute': { ru: 'Время: 1 минута', es: 'Tiempo: 1 minuto', 'en-US': 'Time: 1 minute', fr: 'Temps : 1 minute', it: 'Tempo: 1 minuto', pl: 'Czas: 1 minuta' },
